// 1) Grab and decode from base64 (adjust path if yours differs)
const uploadObj = context.local.data?.['fileUpload']?.['value']?.[0];
if (!uploadObj?.base64) {
  ($set ?? actions.setVariable)('csvPreview', { rows: [], headers: [], totalRecords: 0 });
  return;
}
const base64 = uploadObj.base64.split(',')[1];
const csvText = decodeURIComponent(escape(window.atob(base64)));

// 2) Parse CSV with PapaParse (must be loaded on the page)
const parsed = Papa.parse(csvText, {
  header: true,            // get objects per row
  skipEmptyLines: true,
  dynamicTyping: false,    // we’ll do our own typing
});

// 3) Helper: convert "['AL','AR']" -> ['AL','AR']
function maybeParseArrayLike(value) {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  if (!trimmed.startsWith('[') || !trimmed.endsWith(']')) return value;
  try {
    // Convert single quotes to double quotes so JSON.parse can handle it
    const jsonish = trimmed.replace(/'/g, '"');
    return JSON.parse(jsonish);
  } catch (e) {
    return value; // if it fails, keep original string
  }
}

// 4) Transform rows: turn any array-like strings into arrays
const rows = (parsed.data || []).map(row => {
  const out = {};
  for (const k in row) {
    out[k] = maybeParseArrayLike(row[k]);
  }
  return out;
});

// 5) Build preview object
const headers = parsed.meta?.fields || Object.keys(rows[0] || {});
const totalRecords = rows.length;

// For the visible preview table, you might want strings not arrays:
const previewRows = rows.slice(0, 5).map(r => {
  const display = {};
  headers.forEach(h => {
    const v = r[h];
    display[h] = Array.isArray(v) ? v.join(', ') : v ?? '';
  });
  return display;
});

// 6) Save both the display rows and the raw rows (with real arrays)
const test = ( {
  headers,
  rows: previewRows,        // nice for tables
  rawRows: rows,            // arrays preserved for later upload to Xano
  totalRecords,
});

return test;

