function mapHeaders(headers) {
    const mapped = {};
    const unknown = [];
    const notes = [];

    for (const h of headers) {
        const norm = normalizeHeader(h);
        let target = headerSynonyms[norm];

        if (!target) {
            // fuzzy
            let best = { field: null, score: 0 };
            for (const ph of possibleHeaders) {
                const sc = similarity(norm, ph);
                if (sc > best.score) best = { field: ph, score: sc };
            }
            if (best.score >= 0.6) {
                target = headerSynonyms[best.field];
                notes.push(`Fuzzy matched "${h}" -> ${target} (via "${best.field}")`);
            }
        }

        if (target) {
            if (!mapped[target]) mapped[target] = [];
            mapped[target].push(h);
        } else {
            unknown.push(h);
        }
    }
    return { mapped, unknown, notes };
}

function transformRow(row, headerMap) {
    const pick = (field) => {
        const sources = headerMap[field] || [];
        for (const s of sources) {
            const val = row[s];
            if (val !== undefined && val !== null && String(val).trim() !== "") return val;
        }
        return null;
    };

    // secondary specialties -> IDs (merge Secondary + Other Specialties)
    const secNames = splitMulti(pick("secondary_specialty_ids") || "");
    const secIds = [...new Set(
        secNames
            .map(n => specialtyNameToId[String(n).toUpperCase()] ?? null)
            .filter(v => v != null)
    )];

    // primary specialty: allow ID or name from CSV
    const primarySpecRaw = pick("primary_specialty");
    const primarySpecId =
        primarySpecRaw == null
            ? null
            : (Number.isFinite(Number(primarySpecRaw))
                ? Number(primarySpecRaw)
                : (specialtyNameToId[String(primarySpecRaw).toUpperCase()] ?? null));

    const obj = {
        contact_name: pick("contact_name"),
        primary_certification: pick("primary_certification") ?? null, // pass-through unless you add a cert lookup
        primary_specialty: primarySpecId,
        phone_number: cleanPhone(pick("phone_number")),
        opted_out: false,
        availability_date: toISODate(pick("availability_date")),
        user_id: null,
        profile_image: null,
        secondary_specialty_ids: secIds,
        state: null, // not present in this CSV
        preferred_states: parseStates(pick("preferred_states")),
        shift_preference: bestShift(pick("shift_preference"), pick("profile shift preferences")),
        email: (pick("email") || "")?.toLowerCase() || null,
        recruiting_division: pick("recruiting_division"),
        target_pay: moneyToNumber(pick("target_pay")),
    };

    return obj;
}

function run() {
    // Accept either array-of-objects or CSV text
    const inputCSV = variables[/* csvPreview */'8bef7952-8a67-440e-8b09-94bc07169f22']?.['rows'];
    let inputRows;
    if (Array.isArray(inputCSV)) {
        inputRows = inputCSV;
    } else if (typeof inputCSV === "string") {
        inputRows = parseCsvString(inputCSV);
    } else {
        inputRows = [];
    }

    if (!inputRows.length) {
        return { rows: [], warnings: ["No rows found in $input.csv"], unmapped: [], headerMap: {} };
    }

    const headers = Object.keys(inputRows[0] ?? {});
    const { mapped, unknown, notes } = mapHeaders(headers);

    const outRows = inputRows.map(r => transformRow(r, mapped));
    const warnings = [
        ...notes,
        ...(unknown.length ? [`Unmapped headers: ${unknown.join(", ")}`] : []),
    ];

    return { rows: outRows, warnings, unmapped: unknown, headerMap: mapped };
}

return run();

