// Robust CSV parser (handles quotes, commas, CRLF). If Papa Parse is available, use it.
function parseCSV(text) {
  if (window.Papa && typeof window.Papa.parse === "function") {
    const out = window.Papa.parse(text, { skipEmptyLines: true });
    if (out && !out.errors?.length) return out.data;
  }
  // Fallback tiny parser
  const rows = [];
  let i = 0, field = "", row = [], inQuotes = false;
  const s = text.replace(/\r\n/g, "\n").replace(/\r/g, "\n"); // unify EOL

  while (i < s.length) {
    const ch = s[i];
    if (inQuotes) {
      if (ch === '"') {
        if (s[i + 1] === '"') { field += '"'; i += 2; continue; } // escaped quote
        inQuotes = false; i++; continue;
      } else {
        field += ch; i++; continue;
      }
    } else {
      if (ch === '"') { inQuotes = true; i++; continue; }
      if (ch === ",") { row.push(field); field = ""; i++; continue; }
      if (ch === "\n") { row.push(field); rows.push(row); row = []; field = ""; i++; continue; }
      field += ch; i++; continue;
    }
  }
  // flush last field/row
  row.push(field);
  rows.push(row);

  // drop blank rows
  return rows.filter(r => r.some(cell => (cell ?? "").toString().trim() !== ""));
}

